import React, { useState } from 'react';
import { Link } from 'react-router-dom';

function Project({ id, name, desc, img }) {
  return (
    <Link className="works-item" key={id} to={`/project/${id}`}>
      <div className="picture">
        <div className="content">
          <div className="text">
            <h2>{name}</h2>
            <ul>
              <li>{desc}</li>
            </ul>
          </div>
        </div>
        <img src="{img}" alt="" />
      </div>
    </Link>
  );
}

export default Project;
